<h2>Junior CBC Assessment</h2><form class="card form-grid" method="post"><label>Student<select name="student_id"><?php foreach ($lookups->students() as $s): ?><option value="<?= e($s['id']) ?>"><?= e($s['admission_no'].' '.$s['first_name'].' '.$s['last_name']) ?></option><?php endforeach; ?></select></label><label>Learning area<select name="learning_area_id"><?php foreach ($lookups->learningAreas() as $a): ?><option value="<?= e($a['id']) ?>"><?= e($a['name']) ?></option><?php endforeach; ?></select></label><label>Teacher ID<input type="number" name="teacher_id" required></label><label>Term<input type="number" name="term" min="1" max="3" required></label><label>Year<input type="number" name="academic_year" value="<?= date('Y') ?>" required></label><label>Competency<input name="competency" required></label><label>Descriptor<select name="descriptor"><option>Exceeding Expectations</option><option>Meeting Expectations</option><option>Approaching Expectations</option><option>Below Expectations</option></select></label><label>Assessed at<input type="date" name="assessed_at" value="<?= date('Y-m-d') ?>"></label><label class="wide">Remarks<textarea name="remarks"></textarea></label><button>Save CBC Assessment</button></form>
